from itertools import permutations

class Solution(object):
    def maxGoodNumber(self, nums):
        best = 0
        for perm in permutations(nums):
            # Concatenate binary representations
            result = 0
            for v in perm:
                bits = v.bit_length()
                result = (result << bits) | v
            best = max(best, result)
        return best
